+import { FormRow } from './MoveFormsStyleHelper.tsx';
 import { moveTarget, submitTx } from './MoveFormsTransactionHelper.tsx';
+
+export function AttachChildForm({ address }: { address: string }) {
+  const { mutate: signAndExecuteTransaction } = useSignAndExecuteTransaction();
+  const [digest, setDigest] = useState('');
+
+  const [form, setForm] = useState({
+    parent: '',
+    child: '',
+    externalId: '',
+    name: '',
+    description: '',
+    content: '',
+  });
+
+  const submit = () => {
+    const tx = new Transaction();
+
+    tx.moveCall({
+      target: moveTarget('attach_container_child'),
+      arguments: [
+        tx.object(form.parent),
+        tx.object(form.child),
+        tx.pure.string(form.externalId),
+        tx.pure.string(form.name),
+        tx.pure.string(form.description),
+        tx.pure.string(form.content),
+      ],
+    });
+
+    submitTx(signAndExecuteTransaction, tx, address, setDigest);
+  };
+
+  return (
+    <div className="d-flex justify-content-center mt-4">
+      <div className="w-100" style={{ maxWidth: 560 }}>
+        <h5 className="text-center mb-4">Attach Container Child</h5>
+
+        <FormRow label="Parent Container ID">
+          <input
+            className="form-control form-control-sm rounded-3"
+            placeholder="0x..."
+            value={form.parent}
+            onChange={(e) => setForm({ ...form, parent: e.target.value })}
+          />
+        </FormRow>
+
+        <FormRow label="Child Container ID">
+          <input
+            className="form-control form-control-sm rounded-3"
+            placeholder="0x..."
+            value={form.child}
+            onChange={(e) => setForm({ ...form, child: e.target.value })}
+          />
+        </FormRow>
+
+        <FormRow label="External ID">
+          <input
+            className="form-control form-control-sm rounded-3"
+            value={form.externalId}
+            onChange={(e) => setForm({ ...form, externalId: e.target.value })}
+          />
+        </FormRow>
+
+        <FormRow label="Name">
+          <input
+            className="form-control form-control-sm rounded-3"
+            value={form.name}
+            onChange={(e) => setForm({ ...form, name: e.target.value })}
+          />
+        </FormRow>
+
+        <FormRow label="Description">
+          <input
+            className="form-control form-control-sm rounded-3"
+            value={form.description}
+            onChange={(e) => setForm({ ...form, description: e.target.value })}
+          />
+        </FormRow>
+
+        <FormRow label="Content">
+          <textarea
+            className="form-control form-control-sm rounded-3"
+            rows={3}
+            value={form.content}
+            onChange={(e) => setForm({ ...form, content: e.target.value })}
+          />
+        </FormRow>
+
+        <div className="text-center mt-4">
+          <button
+            className="btn btn-outline-primary btn-sm px-4"
+            onClick={submit}
+          >
+            Attach Child
+          </button>
+        </div>
+
+        {digest && (
+          <div className="text-center small mt-3">
+            Digest: {digest}
+          </div>
+        )}
+      </div>
+    </div>
+  );
+}

